# @MEMO 需求：粘入新版本log自动插入CHANGELOG顶部并推送公开库 | 注意：公开库路径~/zhongqu_public，token用~/zhongqu_token.txt
# 日志格式：## v版本—日期·标题 / ### 变更 / ### 修复 / ### 优化 / ### 架构说明，条目用-开头
import os, subprocess

PUBLIC = os.path.expanduser('~/zhongqu_public')
CHANGELOG = os.path.join(PUBLIC, 'CHANGELOG.md')

SECTION_KEYS = ['变更', '修复', '优化', '架构说明']

def format_log(lines):
    """自动套markdown格式，无论用户粘什么都能对齐"""
    result = []
    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue
        # 版本标题行：v1.x 开头
        if stripped.startswith('v') and '—' in stripped:
            if not stripped.startswith('##'):
                stripped = '## ' + stripped
        # 段落标题：变更/修复/优化/架构说明
        elif any(stripped.startswith(k) for k in SECTION_KEYS):
            if not stripped.startswith('###'):
                stripped = '### ' + stripped.rstrip('：').rstrip(':')
        # 条目：普通文本自动加-
        elif not stripped.startswith('-') and not stripped.startswith('#'):
            stripped = '- ' + stripped
        result.append(stripped)
    return result

print("\n=== 发布更新日志 ===")
print("粘入log内容，完成后单独一行输入 END：\n")

lines = []
while True:
    line = input()
    if line.strip() == 'END':
        break
    lines.append(line)

if not lines:
    print("⚠️ 没有内容")
    input("回车返回...")
else:
    formatted = format_log(lines)
    new_entry = '\n\n'.join(formatted).strip()

    first_line = formatted[0].lstrip('#').strip() if formatted else ''
    commit_msg = first_line or '更新日志'

    # 读取现有CHANGELOG
    if os.path.exists(CHANGELOG):
        with open(CHANGELOG, 'r', encoding='utf-8') as f:
            old = f.read()
    else:
        old = ''

    # 防止重复插入
    version_key = next((l.lstrip('#').strip() for l in formatted if '—' in l and 'v' in l), '')
    if version_key and version_key in old:
        print(f"⚠️ 版本「{version_key}」已存在，跳过插入")
        input("回车返回...")
    else:
        if '# Changelog' in old:
            parts = old.split('# Changelog', 1)
            rest = parts[1].lstrip('\n')
            new_content = f'# Changelog\n\n{new_entry}\n\n---\n\n{rest}'
        else:
            new_content = f'# Changelog\n\n{new_entry}\n\n---\n\n{old}'

        with open(CHANGELOG, 'w', encoding='utf-8') as f:
            f.write(new_content)

        print(f"\n📝 已写入：{commit_msg}")
        print("\n格式预览：")
        for l in formatted[:6]:
            print(f"  {l}")
        if len(formatted) > 6:
            print(f"  ... 共{len(formatted)}行")

        confirm = input("\n确认推送？(y/n)：").strip()
        if confirm == 'y':
            result = subprocess.run(
                f'cd {PUBLIC} && git add CHANGELOG.md && git commit -m "{commit_msg}" && git push',
                shell=True, capture_output=True, text=True
            )
            if result.returncode == 0:
                print(f"✅ 已推送：{commit_msg}")
            else:
                print(f"❌ 推送失败：{result.stderr[:200]}")
        else:
            print("已取消推送，文件已写入本地")

    input("\n回车返回...")

