# @MEMO 需求：包数据库，存包/读index/蒸馏/取全文，自动打标签 | 注意：~/packs/目录，历史包只追加不覆盖，index格式：时间|摘要|标签|文件名

import os
from datetime import datetime

try:
    BASE_DIR = _base_dir
except NameError:
    BASE_DIR = os.path.expanduser("~")

PACKS_DIR = os.path.join(BASE_DIR, "packs")
INDEX_FILE = os.path.join(PACKS_DIR, "index.md")
