# @MEMO 需求：包数据库，存包/读index/蒸馏/取全文，自动打标签 | 注意：~/packs/目录，历史包只追加不覆盖，index格式：时间|摘要|标签|文件名

import os
from datetime import datetime

try:
    BASE_DIR = _base_dir
except NameError:
    BASE_DIR = os.path.expanduser("~")

PACKS_DIR = os.path.join(BASE_DIR, "packs")
INDEX_FILE = os.path.join(PACKS_DIR, "index.md")
CURRENT_FILE = os.path.join(PACKS_DIR, "current.md")

os.makedirs(PACKS_DIR, exist_ok=True)

TAG_RULES = {
    "#架构":   ["架构","中枢","内核","结构","设计"],
    "#协议":   ["协议","指令","格式","存档","规范"],
    "#数据库": ["数据库","packs","index","存储","字段"],
    "#记忆":   ["记忆","注入包","包","蒸馏","种子","锚"],
    "#代码":   ["代码","函数","exec","python","bug","错误"],
    "#身份":   ["借用者","持有者","主权","属人","身份"],
    "#决策":   ["决策","删除","重构","方案","确认","改"],
    "#问题":   ["未解决","张力","偏移","断裂","风险"],
}

def auto_tag(text):
    text_lower = text.lower()
    tags = []
    for tag, keywords in TAG_RULES.items():
        if any(k in text_lower for k in keywords):
            tags.append(tag)
    return " ".join(tags) if tags else "#其他"

def read_block(prompt):
    print(prompt)
    lines = []
    while True:
        line = input()
        if line.strip().upper() == "END":
            break
        lines.append(line)
    return "\n".join(lines).strip()

def read_index():
    if not os.path.exists(INDEX_FILE):
        return []
    with open(INDEX_FILE, encoding="utf-8") as f:
        return [l.strip() for l in f if l.strip() and not l.startswith("#")]

def read_pack_file(filename):
    path = os.path.join(PACKS_DIR, filename)
    if not os.path.exists(path):
        return None
    with open(path, encoding="utf-8") as f:
        return f.read()

def extract_summary(pack_text):
    in_seed = False
    for line in pack_text.splitlines():
        line = line.strip()
        if "种子层" in line:
            in_seed = True
            continue
        if in_seed and line.startswith("【"):
            break
        if in_seed and line and not line.startswith("+") and not line.startswith("-") and not line.startswith("~") and not line.startswith("#"):
            return line[:40]
    return "（无摘要）"

def write_pack(pack_text, summary, tags):
    ts = datetime.now().strftime("%Y-%m-%d_%H%M%S")
    filename = ts + ".md"
    with open(os.path.join(PACKS_DIR, filename), "w", encoding="utf-8") as f:
        f.write(pack_text)
    with open(INDEX_FILE, "a", encoding="utf-8") as f:
        f.write(datetime.now().strftime("%Y-%m-%d %H:%M") + " | " + summary + " | " + tags + " | " + filename + "\n")
    with open(CURRENT_FILE, "w", encoding="utf-8") as f:
        f.write(pack_text)
    return filename

print("\n=== 包 ===")
print("1. 存包")
print("2. 查看索引")
print("3. 取历史包全文")
print("4. 看当前包")
c = input("选择：").strip()

if c == "1":
    index_lines = read_index()
    if index_lines:
        print("\n最近历史包：")
        for l in (index_lines[-5:] if len(index_lines) >= 5 else index_lines):
            print("  " + l)
        print()
    pack_text = read_block("粘贴包内容（END结束）：\n")
    if not pack_text:
        print("（取消）")
    else:
        summary = extract_summary(pack_text)
        tags = auto_tag(pack_text)
        filename = write_pack(pack_text, summary, tags)
        print(f"\n✅ 已存：{filename}")
        print(f"   摘要：{summary}")
        print(f"   标签：{tags}")
        print(f"✅ index、current已更新")

elif c == "2":
    lines = read_index()
    if not lines:
        print("（index为空）")
    else:
        print(f"\n共 {len(lines)} 个包：\n")
        for l in lines:
            print("  " + l)

elif c == "3":
    lines = read_index()
    if not lines:
        print("（无历史包）")
    else:
        print("\n历史包列表：")
        for i, l in enumerate(lines):
            print(f"  {i+1}. {l}")
        nums = input("\n输入编号（逗号分隔）：").strip()
        for n in nums.split(","):
            n = n.strip()
            if not n.isdigit():
                continue
            idx = int(n) - 1
            if 0 <= idx < len(lines):
                parts = lines[idx].split(" | ")
                filename = parts[-1] if parts else ""
                content = read_pack_file(filename)
                if content:
                    print(f"\n{'='*40}")
                    print(f"  {lines[idx]}")
                    print(f"{'='*40}")
                    print(content)
                else:
                    print(f"  ⚠️ 文件不存在：{filename}")

elif c == "4":
    if not os.path.exists(CURRENT_FILE):
        print("（current.md不存在）")
    else:
        with open(CURRENT_FILE, encoding="utf-8") as f:
            print(f.read())

else:
    print("无效选择")

input("\n回车返回...")
